/* ============================================================================
   CRM — mini-ClickUp style inbox (CLIENT-ONLY PROTOTYPE)
   Everything here is in-memory and dynamic. There are NO Supabase/database
   calls anywhere in this module — it exists purely to review the UI/flow.
   Structure: Hubs (collapsible sidebar) -> Boards (with members) -> category
   tabs (Chats / Complaints / Refunds / Approvals, dynamic) -> conversations.
   A conversation starts as a chat and can be "converted to a ticket" of a type.
   ============================================================================ */
let CRM=null;
function _crmInit(){if(CRM)return;CRM={_loaded:false,_loading:false,_err:null,hubs:[],boards:[],categories:[],convos:[],sel:{hubId:null,boardId:null,category:'Chats',convoId:null,threadId:null,channelId:null},sidebarCollapsed:false,collapsedHubs:{},collapsedChannels:{},channels:[],chanMembersOpen:false,_chanMemId:null,activity:[],settings:{},activityOpen:false,boardSettingsOpen:false,globalSettingsOpen:false,_bsBoardId:null,search:'',compose:{images:[]},editMsgId:null,fwdMsgId:null,reads:{},boardView:(function(){try{return JSON.parse(localStorage.getItem('bridge_crm_views')||'{}');}catch(e){return{};}})()};}
const _crmSeeAll=()=>isAdmin()||can('crm','manage');
function _crmChan(id){return (CRM.channels||[]).find(function(c){return c.id===id;});}
function _crmChanMember(c){return !!(c&&(c.members||[]).indexOf(S.uid)>=0);}
function _crmBoardVisible(b){if(_crmSeeAll())return true;if((b.members||[]).indexOf(S.uid)>=0)return true;return _crmChanMember(_crmChan(b.channelId));}
function _crmChanVisible(c){if(_crmSeeAll())return true;if(_crmChanMember(c))return true;return (CRM.boards||[]).some(function(b){return b.channelId===c.id&&(b.members||[]).indexOf(S.uid)>=0;});}
function _crmVisibleBoards(){return (CRM.boards||[]).filter(_crmBoardVisible);}
function _crmVisibleBoardIds(){var s={};_crmVisibleBoards().forEach(b=>s[b.id]=1);return s;}
const _crmPri={Low:['#6B7280','#F3F4F6'],Medium:['#B45309','#FFF7ED'],High:['#B91C1C','#FEF2F2'],Critical:['#6D28D9','#F5F3FF']};
const _crmTime=iso=>{try{return new Date(iso).toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'});}catch(e){return'';}};
const _crmDT=iso=>{try{return new Date(iso).toLocaleString('en-GB',{day:'numeric',month:'short',year:'numeric',hour:'numeric',minute:'2-digit'});}catch(e){return'';}};
const _crmRel=iso=>{if(!iso)return'';const s=(Date.now()-new Date(iso).getTime())/1000;if(s<60)return'now';if(s<3600)return Math.floor(s/60)+'m';if(s<86400)return Math.floor(s/3600)+'h';return Math.floor(s/86400)+'d';};
const _crmBoard=id=>CRM.boards.find(b=>b.id===id);
const _crmConvo=id=>CRM.convos.find(c=>c.id===id);
/* ── v2: unread + due-date helpers ── */
function _crmUnread(c){if(!c||!c.lastAt||!S.uid)return false;var last=(c.messages||[])[(c.messages||[]).length-1];if(last&&!last.fromCustomer&&last.senderId===S.uid)return false;var seen=(CRM.reads||{})[c.id];return !seen||String(c.lastAt)>String(seen);}
function _crmUnreadCount(boardId){return (CRM.convos||[]).filter(function(c){return c.boardId===boardId&&_crmUnread(c);}).length;}
function _crmMarkRead(id){var c=_crmConvo(id);if(!c||!S.uid)return;var now=new Date().toISOString();var seen=(CRM.reads||{})[id];if(seen&&String(seen)>=String(c.lastAt||''))return;if(!CRM.reads)CRM.reads={};CRM.reads[id]=now;sbWrite({table:'crm_reads',op:'upsert',values:{user_id:S.uid,conversation_id:id,last_seen_at:now},opts:{onConflict:'user_id,conversation_id'}},{label:'Read state',silent:true});}
function _crmDueMeta(c){if(!c||!c.isTicket||!c.dueDate)return null;var over=c.dueDate<todayISO()&&c.status!=='Resolved'&&c.status!=='Closed';var today=c.dueDate===todayISO();return{overdue:over,today:today,label:fmtS(c.dueDate),color:over?'#DC2626':today?'#B45309':'#6B7280',bg:over?'#FEF2F2':today?'#FFFBEB':'#F3F4F6'};}
function _crmCats(board){var c=board&&board.settings&&board.settings.categories;return (c&&c.length)?c:[];}
const _crmFirst=u=>u?(fullName(u).split(' ')[0]||fullName(u)):'';
const _CRM_EMO=['\u{1F44D}','❤️','\u{1F602}','\u{1F389}','\u{1F62E}'];
function _crmCustAv(name,sz){sz=sz||34;var n=(name||'?').trim();var ini=(n[0]||'?').toUpperCase();var h=0;for(var i=0;i<n.length;i++)h+=n.charCodeAt(i);var bg=['#0E9F6E','#2563EB','#D97706','#7C3AED','#DB2777','#0891B2'][h%6];return'<div style="width:'+sz+'px;height:'+sz+'px;border-radius:50%;background:'+bg+';color:#fff;display:grid;place-items:center;font-size:'+Math.round(sz*0.4)+'px;font-weight:700;flex-shrink:0">'+esc(ini)+'</div>';}
function _crmAt(t){return esc(t||'').replace(/@(\w+)/g,'<span style="background:#E6F7F0;color:#0B7A54;font-weight:700;border-radius:4px;padding:0 3px">@$1</span>');}
function _crmImgs(imgs){if(!imgs||!imgs.length)return'';return'<div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:6px">'+imgs.map(function(s){return'<img src="'+s+'" onclick="App._bigImg&&App._bigImg(this.src)" style="width:130px;height:96px;object-fit:cover;border-radius:10px;border:1px solid rgba(0,0,0,.08);cursor:pointer"/>';}).join('')+'</div>';}
async function _crmProvisionDefault(){var hid=uid('hub'),cid=uid('chn'),bid=uid('brd');CRM.hubs.push({id:hid,name:'General',icon:'msg'});CRM.channels.push({id:cid,hubId:hid,name:'General',members:S.uid?[S.uid]:[]});CRM.boards.push({id:bid,channelId:cid,hubId:hid,name:'Chat',members:[],settings:{type:'chat'}});CRM.sel.hubId=hid;CRM.sel.channelId=cid;CRM.sel.boardId=bid;try{await sb.from('crm_hubs').insert({id:hid,name:'General',icon:'msg',created_by:S.uid||null,sort:0});await sb.from('crm_channels').insert({id:cid,hub_id:hid,name:'General',created_by:S.uid||null,sort:0});await sb.from('crm_boards').insert({id:bid,channel_id:cid,hub_id:hid,name:'Chat',created_by:S.uid||null,sort:0,settings:{type:'chat'}});if(S.uid)await sb.from('crm_channel_members').insert({channel_id:cid,user_id:S.uid});}catch(e){console.warn('[CRM default]',e&&e.message);}}
async function _crmLoad(){
  if(CRM._loading)return;CRM._loading=true;CRM._err=null;
  try{
    const R=await Promise.all([
      sb.from('crm_hubs').select('*').order('sort',{ascending:true}),
      sb.from('crm_boards').select('*').order('sort',{ascending:true}),
      sb.from('crm_board_members').select('*'),
      sb.from('crm_categories').select('*').order('sort',{ascending:true}),
      sb.from('crm_conversations').select('*').order('last_at',{ascending:false}),
      sb.from('crm_messages').select('*').order('created_at',{ascending:true}),
      sb.from('crm_activity').select('*').order('created_at',{ascending:false}).limit(500),
      sb.from('workspace_settings').select('*').eq('key','crm_settings'),
      sb.from('crm_channels').select('*').order('sort',{ascending:true}),
      sb.from('crm_channel_members').select('*'),
      sb.from('crm_reads').select('*').eq('user_id',S.uid||'')
    ]);
    if(R[0].error)throw R[0].error;
    CRM.hubs=(R[0].data||[]).map(r=>({id:r.id,name:r.name,icon:r.icon||'folder'}));
    const mb={};(R[2].data||[]).forEach(r=>{(mb[r.board_id]=mb[r.board_id]||[]).push(r.user_id);});
    CRM.boards=(R[1].data||[]).map(r=>({id:r.id,hubId:r.hub_id,name:r.name,members:mb[r.id]||[],settings:r.settings||{},channelId:r.channel_id}));
    CRM.categories=(R[3].data||[]).map(r=>r.name);
    const mc={};(R[5].data||[]).forEach(r=>{(mc[r.conversation_id]=mc[r.conversation_id]||[]).push({id:r.id,senderId:r.sender_id,fromCustomer:r.from_customer,name:r.name,text:r.body||'',images:r.images||[],at:r.created_at,reactions:r.reactions||{},parentId:r.parent_id||null,edited:!!r.edited_at});});
    CRM.convos=(R[4].data||[]).map(r=>({id:r.id,boardId:r.board_id,title:r.title,customer:r.customer,channel:r.channel,isTicket:r.is_ticket,ticketType:r.ticket_type,priority:r.priority||'Medium',status:r.status||'Open',assignedTo:r.assigned_to||null,decision:r.decision||null,decidedBy:r.decided_by||null,decidedAt:r.decided_at||null,fields:r.fields||{},dueDate:r.due_date||null,createdAt:r.created_at,lastAt:r.last_at,messages:mc[r.id]||[]}));CRM.activity=(R[6].data||[]).map(function(r){return{id:r.id,conversationId:r.conversation_id,boardId:r.board_id,actor:r.actor,action:r.action,detail:r.detail||'',at:r.created_at};});try{var _gs=R[7].data&&R[7].data[0]&&R[7].data[0].value;if(_gs&&typeof _gs==='object')CRM.settings=_gs;}catch(e){}var _cm={};((R[9]&&R[9].data)||[]).forEach(function(r){(_cm[r.channel_id]=_cm[r.channel_id]||[]).push(r.user_id);});CRM.channels=((R[8]&&R[8].data)||[]).map(function(r){return{id:r.id,hubId:r.hub_id,name:r.name,members:_cm[r.id]||[]};});CRM.reads={};((R[10]&&R[10].data)||[]).forEach(function(r){CRM.reads[r.conversation_id]=r.last_seen_at;});
    if(!CRM.hubs.length&&can('crm','create')&&S.uid)await _crmProvisionDefault();
    const vb=_crmVisibleBoards();
    if(!CRM.sel.boardId||!vb.some(x=>x.id===CRM.sel.boardId)){var fb=vb[0];CRM.sel.boardId=fb?fb.id:null;var _fc=fb?_crmChan(fb.channelId):null;CRM.sel.channelId=_fc?_fc.id:null;CRM.sel.hubId=_fc?_fc.hubId:null;}
  }catch(e){CRM._err=(e&&e.message)||'Failed to load';console.warn('[CRM load]',CRM._err);}
  CRM._loaded=true;CRM._loading=false;rr();
}
const _crmStyle='<style>.crm-only-mob{display:none!important}@media(max-width:767px){.crm-fs{bottom:60px!important}.crm-nav{position:absolute!important;left:0;top:0;bottom:0;z-index:40;width:82%!important;max-width:300px;transform:translateX(-100%);transition:transform .2s;box-shadow:4px 0 26px rgba(0,0,0,.22)}.crm-nav.crmopen{transform:none!important}.crm-listcol{width:100%!important;max-width:none!important;min-width:0!important}.crm-chatpane{display:none!important}.crm-hasconvo .crm-listcol{display:none!important}.crm-hasconvo .crm-chatpane{display:flex!important}.crm-hasconvo .crm-boardbar{display:none!important}.crm-hasconvo .crm-tabsrow{display:none!important}.crm-only-mob{display:inline-flex!important}.crm-hide-mob{display:none!important}.crm-chx,.crm-del,.crm-bdel,.crm-hdel,.crm-macts{display:flex!important}}.crm-chrow:hover .crm-chx{display:grid!important}.crm-scroll::-webkit-scrollbar{width:9px;height:9px}.crm-scroll::-webkit-scrollbar-thumb{background:#E3E5E9;border-radius:9px}.crm-scroll::-webkit-scrollbar-track{background:transparent}.crm-row:hover .crm-del{display:grid!important}.crm-brd:hover .crm-bdel{display:grid!important}.crm-hub:hover .crm-hdel{display:grid!important}.crm-tab:hover .crm-tx{display:inline-flex!important}.crm-msg:hover .crm-macts{display:flex!important}.crm-colh:hover .crm-colx{display:inline-flex!important}.crm-cell:focus{border-color:#0E9F6E!important;background:#fff!important}.crm-trow:hover{background:#FAFBFC}</style>';
function _crmEmpty(icon,title,sub,btn){return'<div style="flex:1;display:grid;place-items:center;padding:40px"><div style="text-align:center;max-width:360px"><div style="width:56px;height:56px;border-radius:16px;background:#F0FBF6;color:#0E9F6E;display:grid;place-items:center;margin:0 auto 14px">'+ic(icon,'w-7 h-7')+'</div><div class="fd" style="font-size:16px;font-weight:800;color:#15171C">'+esc(title)+'</div><div style="font-size:13px;color:#9CA3AF;margin-top:5px;line-height:1.5">'+esc(sub)+'</div>'+(btn||'')+'</div></div>';}
