  return'<div class="crm-row" onclick="'+(showBoard?'App._crmOpenResult':'App._crmSelConvo')+'(\''+c.id+'\')" style="position:relative;cursor:pointer;padding:11px 12px;border-bottom:1px solid #F3F4F6;background:'+(active?'#F0FBF6':unread?'#F7FEFB':'#fff')+';border-left:3px solid '+(active?'#0E9F6E':unread?'#34D399':'transparent')+'">'
