App._crmNewChannel=async(hubId)=>{if(!can('crm','create'))return toast('No permission to create','err');var n=prompt('New channel name (e.g. CS<>OPS):');if(!n||!n.trim())return;var cid=uid('chn'),bid=uid('brd');CRM.channels.push({id:cid,hubId:hubId,name:n.trim(),members:S.uid?[S.uid]:[]});CRM.boards.push({id:bid,channelId:cid,hubId:hubId,name:'Chat',members:[],settings:{type:'chat'}});CRM.collapsedHubs[hubId]=false;CRM.sel.hubId=hubId;CRM.sel.channelId=cid;CRM.sel.boardId=bid;CRM.sel.convoId=null;rr();try{await sb.from('crm_channels').insert({id:cid,hub_id:hubId,name:n.trim(),created_by:S.uid||null,sort:CRM.channels.length});await sb.from('crm_boards').insert({id:bid,channel_id:cid,hub_id:hubId,name:'Chat',created_by:S.uid||null,sort:0,settings:{type:'chat'}});if(S.uid)await sb.from('crm_channel_members').insert({channel_id:cid,user_id:S.uid});}catch(e){toast('Saved locally, sync failed','warn');}};
App._crmDelChannel=async(id)=>{if(!can('crm','delete'))return toast('No permission to delete','err');var c=_crmChan(id);if(!c)return;if(!confirm('Delete channel "'+c.name+'" and all its boards & conversations?'))return;var bids=CRM.boards.filter(function(b){return b.channelId===id;}).map(function(b){return b.id;});CRM.channels=CRM.channels.filter(function(x){return x.id!==id;});CRM.boards=CRM.boards.filter(function(b){return b.channelId!==id;});CRM.convos=CRM.convos.filter(function(cv){return bids.indexOf(cv.boardId)<0;});if(CRM.sel.channelId===id){CRM.sel.channelId=null;CRM.sel.boardId=null;CRM.sel.convoId=null;}rr();try{await sb.from('crm_channels').delete().eq('id',id);}catch(e){}};
App._crmTogChannel=(id)=>{CRM.collapsedChannels[id]=!CRM.collapsedChannels[id];rr();};
App._crmSelChannel=(id)=>{CRM.collapsedChannels[id]=false;var vb=CRM.boards.filter(function(x){return x.channelId===id&&_crmBoardVisible(x);});var b=vb[0]||CRM.boards.filter(function(x){return x.channelId===id;})[0];if(b){App._crmSelBoard(b.id);}else{var c=_crmChan(id);CRM.sel.channelId=id;CRM.sel.hubId=c?c.hubId:null;CRM.sel.boardId=null;CRM.sel.convoId=null;rr();}};
