App._crmChanAddMember=async(uid2)=>{if(!can('crm','create'))return;var c=_crmChan(CRM._chanMemId);if(!c)return;if((c.members||[]).indexOf(uid2)<0)c.members.push(uid2);rr();try{await sb.from('crm_channel_members').insert({channel_id:c.id,user_id:uid2});}catch(e){}};
